import * as fs from "node:fs";
import * as https from "node:https";
import * as path from "node:path";
import { pipeline } from "node:stream/promises";
import * as semver from "semver";
import { Extract } from "unzipper";
import * as vscode from "vscode";
import { BACKEND_HOSTNAME } from "./environment";
import { logger } from "./logger";

const VERSIONS_URL = `${BACKEND_HOSTNAME}/public/versions`;

interface VersionInfo {
  version: string;
  minimumExtensionVersion?: string;
  downloadUrl: string;
  updatedAt: string;
}

export function getStoragePath(context: vscode.ExtensionContext): vscode.Uri {
  return context.globalStorageUri;
}

export function getEditorPath(context: vscode.ExtensionContext): vscode.Uri {
  return vscode.Uri.joinPath(context.globalStorageUri, "editor");
}

export async function checkForEditorUpdate(
  context: vscode.ExtensionContext,
  initial: boolean,
): Promise<void> {
  const editorPath = getEditorPath(context).fsPath;
  logger.info(`Editor path: ${editorPath}`);

  try {
    const versionInfo = await fetchLatestVersion();
    logger.info(`Latest version: ${versionInfo.version}`);

    if (!checkVersionCompatibility(versionInfo)) {
      logger.warn(
        `This editor version requires extension version ${versionInfo.minimumExtensionVersion} or higher. Skipping editor bundle update.`,
      );
      return;
    }

    const needsUpdate = await checkIfUpdateNeeded(context, versionInfo);
    logger.info(`Needs update: ${needsUpdate}`);

    if (
      fs.existsSync(editorPath) &&
      hasEditorContent(editorPath) &&
      !needsUpdate
    ) {
      logger.info("Editor bundle is up to date");
      return;
    }

    if (needsUpdate) {
      logger.info(`Updating editor bundle to version ${versionInfo.version}`);
    } else {
      logger.info("Downloading editor bundle...");
    }

    await downloadAndExtractBundle(context, versionInfo);
    await saveCurrentVersion(context, versionInfo);

    if (hasEditorContent(editorPath)) {
      logger.info("Editor bundle downloaded and extracted successfully");

      if (!initial) {
        const resp = await vscode.window.showInformationMessage(
          "Pencil updated. Reload the extension",
          "Reload",
          "Ignore",
        );

        if (resp === "Ignore") {
          return;
        } else if (resp === "Reload") {
          await vscode.commands.executeCommand(
            "workbench.action.restartExtensionHost",
          );
        }
      }
    } else {
      throw new Error("Downloaded bundle appears to be incomplete");
    }
  } catch (error) {
    logger.error("Failed to ensure editor bundle:", JSON.stringify(error));

    if (initial) {
      await vscode.window.showErrorMessage("Failed to start Pencil extension");
      throw error;
    }
  }
}

function hasEditorContent(editorDir: string): boolean {
  const indexHtmlPath = path.join(editorDir, "index.html");
  const assetsDir = path.join(editorDir, "assets");

  return fs.existsSync(indexHtmlPath) && fs.existsSync(assetsDir);
}

async function fetchLatestVersion(): Promise<VersionInfo> {
  const response = await fetch(VERSIONS_URL);

  if (!response.ok) {
    throw new Error(`Failed to fetch version info: ${response.status}`);
  }

  return response.json() as any;
}

function checkVersionCompatibility(versionInfo: VersionInfo): boolean {
  if (!versionInfo.minimumExtensionVersion) {
    return true;
  }

  const extensionVersion = vscode.extensions.getExtension(
    "highagency.pencildev",
  )?.packageJSON.version;
  if (!extensionVersion) {
    logger.warn("Could not determine extension version");
    return true;
  }

  const isCompatible = semver.gte(
    extensionVersion,
    versionInfo.minimumExtensionVersion,
  );
  if (!isCompatible) {
    logger.warn(
      `Extension version ${extensionVersion} is below minimum required ${versionInfo.minimumExtensionVersion}`,
    );
  }

  return isCompatible;
}

async function checkIfUpdateNeeded(
  context: vscode.ExtensionContext,
  latestVersion: VersionInfo,
): Promise<boolean> {
  const storagePath = getStoragePath(context).fsPath;
  const currentVersionPath = path.join(storagePath, "current-version.json");

  if (!fs.existsSync(currentVersionPath)) {
    return true; // No version info, needs update
  }

  try {
    const currentVersionData = fs.readFileSync(currentVersionPath, "utf8");
    const currentVersion = JSON.parse(currentVersionData);
    return semver.gt(latestVersion.version, currentVersion.version);
  } catch (error) {
    logger.error("Failed to read current version:", error);
    return true; // Error reading, assume needs update
  }
}

async function saveCurrentVersion(
  context: vscode.ExtensionContext,
  versionInfo: VersionInfo,
): Promise<void> {
  const storagePath = getStoragePath(context).fsPath;
  const currentVersionPath = path.join(storagePath, "current-version.json");

  fs.writeFileSync(currentVersionPath, JSON.stringify(versionInfo, null, 2));
}

async function downloadAndExtractBundle(
  context: vscode.ExtensionContext,
  versionInfo: VersionInfo,
): Promise<void> {
  const storagePath = getStoragePath(context).fsPath;
  const editorPath = getEditorPath(context).fsPath;

  if (!fs.existsSync(storagePath)) {
    fs.mkdirSync(storagePath, { recursive: true });
  }

  // Remove existing editor directory if it exists
  if (fs.existsSync(editorPath)) {
    fs.rmSync(editorPath, { recursive: true, force: true });
  }

  const tempZipPath = path.join(storagePath, "editor-bundle.zip");

  try {
    await downloadFile(versionInfo.downloadUrl, tempZipPath);

    await extractZip(tempZipPath, storagePath);

    const outDir = path.join(storagePath, "out");
    if (fs.existsSync(outDir)) {
      fs.renameSync(outDir, editorPath);
    }
  } finally {
    if (fs.existsSync(tempZipPath)) {
      fs.unlinkSync(tempZipPath);
    }
  }
}

function downloadFile(url: string, outputPath: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const file = fs.createWriteStream(outputPath);

    https
      .get(url, (response) => {
        if (response.statusCode !== 200) {
          reject(
            new Error(`Download failed with status: ${response.statusCode}`),
          );
          return;
        }

        pipeline(response, file)
          .then(() => resolve())
          .catch(reject);
      })
      .on("error", reject);
  });
}

function extractZip(zipPath: string, extractDir: string): Promise<void> {
  return new Promise((resolve, reject) => {
    fs.createReadStream(zipPath)
      .pipe(Extract({ path: extractDir }))
      .on("close", resolve)
      .on("error", reject);
  });
}
