import ShortUniqueId from "short-unique-id";
// Using 5 length unique IDs means a ~4e-8 probability for collision within 1000
// nodes, which should be sufficient for our use case.
const { randomUUID } = new ShortUniqueId({ length: 5 });
const { randomUUID: randomLetter } = new ShortUniqueId({
    length: 1,
    dictionary: "alpha",
});
/**
 * Generates a unique ID for nodes in .pen documents.
 *
 * IDs always start with a letter so they're valid JS identifiers —
 * `batch_design` parses operations like `U(abc12, ...)` as JS, which breaks if
 * an ID starts with a digit.
 */
export function createUniqueId() {
    const id = randomUUID();
    return /^[0-9]/.test(id) ? randomLetter() + id : id;
}
