import * as vscode from "vscode";
import { Disposable } from "./dispose";

type SaveOptions = {
  assignNewFileToken?: boolean;
  destinationUri?: vscode.Uri;
};

export class PencilDocument
  extends Disposable
  implements vscode.CustomDocument
{
  private content: string;
  onSave?: (uri: vscode.Uri, options?: SaveOptions) => Promise<string>;

  constructor(
    public readonly uri: vscode.Uri,
    initialContent: string,
  ) {
    super();

    this.content = initialContent;
  }

  dispose(): void {
    this._onDidDispose.fire();
    super.dispose();
  }

  getContent(): string {
    return this.content;
  }

  setContent(content: string): void {
    this.content = content;
  }

  private readonly _onDidDispose = this._register(
    new vscode.EventEmitter<void>(),
  );

  public readonly onDidDispose = this._onDidDispose.event;

  private readonly _onDidChange = this._register(
    new vscode.EventEmitter<{
      readonly label: string;
      undo(): void;
      redo(): void;
    }>(),
  );

  public readonly onDidChange = this._onDidChange.event;

  async save(cancellation: vscode.CancellationToken): Promise<void> {
    await this.saveAs(this.uri, cancellation);
  }

  async saveAs(
    targetResource: vscode.Uri,
    _cancellation: vscode.CancellationToken,
    options?: SaveOptions,
  ): Promise<void> {
    await this.saveWithCustomPaths(targetResource, options);
  }

  private async saveWithCustomPaths(
    serializationUri: vscode.Uri,
    options?: SaveOptions,
  ): Promise<void> {
    if (!this.onSave) {
      return;
    }
    const destinationUri = options?.destinationUri ?? serializationUri;
    this.content = await this.onSave(serializationUri, {
      assignNewFileToken: options?.assignNewFileToken,
    });
    await vscode.workspace.fs.writeFile(
      destinationUri,
      Buffer.from(this.getContent(), "utf8"),
    );
  }

  async revert(_cancellation: vscode.CancellationToken): Promise<void> {
    const diskContent = await vscode.workspace.fs.readFile(this.uri);
    this.content = Buffer.from(diskContent).toString("utf8");
  }

  async backup(
    destination: vscode.Uri,
    _cancellation: vscode.CancellationToken,
  ): Promise<vscode.CustomDocumentBackup> {
    await vscode.workspace.fs.createDirectory(
      vscode.Uri.joinPath(destination, ".."),
    );
    await this.saveWithCustomPaths(this.uri, { destinationUri: destination });

    return {
      id: destination.toString(),
      delete: async () => {
        try {
          await vscode.workspace.fs.delete(destination);
        } catch {
          // noop
        }
      },
    };
  }
}
