import * as path from "node:path";
import { IPCDeviceManager, TransportServerManager } from "@ha/ipc";
import { getMcpConfiguration } from "@ha/mcp";
import type { MCPIntegration } from "@ha/shared";
import * as Sentry from "@sentry/node";
import * as vscode from "vscode";
import { checkForEditorUpdate } from "./bundle-manager";
import { PENCIL_EXTENSION_ID, PENCIL_MCP_NAME } from "./contants";
import { IS_DEV, PACKAGE_VERSION, SENTRY_DSN } from "./environment";
import { logger } from "./logger";
import { PencilEditorProvider } from "./pencil-editor-provider";
import { SidebarProvider } from "./sidebar-provider";
import { checkForExtensionUpdate } from "./versions-util";
import { VsCodeMCPAdapter } from "./vscode-mcp-adapter";
import { createAndOpenDocument, getThemeKind } from "./vscode-resource-device";

const EXTENSION_PATH_FRAGMENT = PENCIL_EXTENSION_ID.replace(".", path.sep);

Sentry.init({
  dsn: SENTRY_DSN,

  // Include the package version as the release version
  release: PACKAGE_VERSION,

  // Intentionally sending PIIs like IP addresses, user IDs for now.
  sendDefaultPii: true,

  // Disable client metrics uploads.
  sendClientReports: false,

  sampleRate: 0.2,

  // Disable Sentry in development environment
  enabled: !IS_DEV,
  beforeSend: (event) => {
    const frames =
      event.exception?.values?.flatMap((exc) => exc.stacktrace?.frames || []) ||
      [];

    if (frames.length === 0) {
      return null;
    }

    const fromThisExtension = frames.some(
      (f) =>
        typeof f.filename === "string" &&
        f.filename.includes(EXTENSION_PATH_FRAGMENT),
    );

    // Only report if stack trace contains our extension's files
    if (!fromThisExtension) {
      return null;
    }

    return event;
  },
});

Sentry.setContext("ide", {
  name: vscode.env.appName,
  vscodeVersion: vscode.version,
  remote: vscode.env.remoteName ?? "local",
  uiKind: vscode.env.uiKind === vscode.UIKind.Desktop ? "desktop" : "web",
});

let transportServer: TransportServerManager;
let mcpAdapter: VsCodeMCPAdapter;
let isLeftSidebarVisible = true;

export async function activate(context: vscode.ExtensionContext) {
  logger.info("activated");

  if (IS_DEV) {
    logger.show();
  }

  if (!IS_DEV) {
    await checkForEditorUpdate(context, true);
  }

  mcpAdapter = new VsCodeMCPAdapter(context);

  transportServer = new TransportServerManager(logger, mcpAdapter.getAppName());
  transportServer.start();

  const ipcDeviceManager = new IPCDeviceManager(
    transportServer,
    logger,
    mcpAdapter.getInstallationPath(),
    mcpAdapter.getAppName(),
  );
  const sidebarProvider = new SidebarProvider(context);
  const editorProvider = new PencilEditorProvider(
    context,
    ipcDeviceManager,
    mcpAdapter,
    sidebarProvider,
  );

  transportServer.on("ready", async (socketPath: string) => {
    logger.info(`Transport server ready on ${socketPath}`);

    const enabledIntegrations = context.globalState.get<
      MCPIntegration[] | undefined
    >("enabledIntegrations", undefined);

    await mcpAdapter.setupIntegrations(enabledIntegrations);

    if (vscode.env.appName === "Cursor") {
      const mcpConfig = getMcpConfiguration({
        folderPath: mcpAdapter.getInstallationPath(),
        appName: mcpAdapter.getAppName(),
        agentName: "cursorIDE",
      });

      if (mcpConfig.transport === "stdio") {
        vscode.cursor.mcp.registerServer({
          name: PENCIL_MCP_NAME,
          server: {
            args: mcpConfig.args,
            command: mcpConfig.command,
            env: mcpConfig.env,
          },
        });
      }
    }
  });

  ipcDeviceManager.setWorkspaces(mapWorkspaceFolders());

  ipcDeviceManager.proxyMcpToolCallRequests();

  ipcDeviceManager.on("open-temporary-document", async (name: string) => {
    await createAndOpenDocument(context, name);
  });

  context.subscriptions.push(
    vscode.commands.registerCommand("pencil.newFile", () =>
      createAndOpenDocument(context, "new"),
    ),
    vscode.commands.registerCommand("pencil.toggleDesignMode", () =>
      toggleDesignMode(),
    ),
    vscode.commands.registerCommand(
      "pencil.setLeftSidebarVisible",
      (visible: boolean) => setLeftSidebarVisible(visible as boolean),
    ),
    vscode.commands.registerCommand("pencil.openWelcomeDocument", () =>
      createAndOpenDocument(context, "welcome"),
    ),
    vscode.commands.registerCommand("pencil.openShadcnDocument", () =>
      createAndOpenDocument(context, "shadcn"),
    ),
    vscode.commands.registerCommand("pencil.openHaloDocument", () =>
      createAndOpenDocument(context, "halo"),
    ),
    vscode.commands.registerCommand("pencil.openLunarisDocument", () =>
      createAndOpenDocument(context, "lunaris"),
    ),
    vscode.commands.registerCommand("pencil.openNitroDocument", () =>
      createAndOpenDocument(context, "nitro"),
    ),
    vscode.commands.registerCommand("pencil.openDemoDocument", () =>
      createAndOpenDocument(context, "demo"),
    ),
    vscode.commands.registerCommand(
      "pencil.openRawDesignFile",
      (uri: vscode.Uri) => openRawDesignFile(uri),
    ),
    vscode.commands.registerCommand("pencil.showSettings", async () => {
      const tabs = vscode.window.tabGroups.all.flatMap((group) => group.tabs);

      const isPencilActive = tabs.find((tab) => {
        const input = tab.input;
        if (input instanceof vscode.TabInputCustom) {
          return (
            input.viewType === PencilEditorProvider.viewType && tab.isActive
          );
        }
        return false;
      });

      if (!isPencilActive) {
        await createAndOpenDocument(context, "new");
      }

      ipcDeviceManager.notifyAll("open-settings", {});
    }),
    vscode.window.registerCustomEditorProvider(
      PencilEditorProvider.viewType,
      editorProvider,
      {
        webviewOptions: { retainContextWhenHidden: true },
      },
    ),
    vscode.workspace.onDidChangeWorkspaceFolders(() => {
      ipcDeviceManager.setWorkspaces(mapWorkspaceFolders());
    }),
    vscode.window.onDidChangeActiveColorTheme((theme) => {
      ipcDeviceManager.notifyAll("color-theme-changed", {
        theme: getThemeKind(theme.kind),
      });
    }),
    vscode.window.registerTreeDataProvider("pencil.sidebar", sidebarProvider),
    vscode.commands.registerCommand("pencil.clearRecentFiles", () => {
      sidebarProvider.clearRecentFiles();
    }),
  );

  const statusBarItem = vscode.window.createStatusBarItem(
    vscode.StatusBarAlignment.Left,
    100,
  );
  statusBarItem.command = "pencil.newFile";
  statusBarItem.text = "$(pencil) Pencil";
  statusBarItem.tooltip = "Create new Pencil file";
  statusBarItem.color = "#DCBB00";
  statusBarItem.backgroundColor = new vscode.ThemeColor(
    "statusBarItem.prominentBackground",
  );
  statusBarItem.show();
  context.subscriptions.push(statusBarItem);

  processFirstRun(context);

  // Check for extension updates every 10 minutes.
  if (!IS_DEV) {
    await checkForExtensionUpdate();

    setInterval(
      async () => {
        const indicatedUpdate = await checkForExtensionUpdate();

        if (!indicatedUpdate) {
          await checkForEditorUpdate(context, false);
        }
      },
      10 * 60 * 1000,
    );
  }
}

export async function deactivate() {
  logger.info("deactivated");

  if (transportServer) {
    transportServer.stop();
  }

  if (mcpAdapter) {
    await mcpAdapter.cleanup();
  }

  if (vscode.env.appName === "Cursor") {
    vscode.cursor.mcp.unregisterServer(PENCIL_MCP_NAME);
  }

  logger.dispose();
}

async function toggleDesignMode() {
  logger.info("toggleDesignMode");

  try {
    if (isLeftSidebarVisible) {
      await closeLeftSidebar();
      await closeRightSidebar();
    } else {
      await openLeftSidebar();
      await openRightSidebar();
    }
  } catch (error) {
    logger.error("Error when toggling design mode", error);
  }
}

async function setLeftSidebarVisible(visible: boolean) {
  logger.info("setLeftSidebarVisible", visible);

  try {
    if (visible) {
      await openLeftSidebar();
    } else {
      await closeLeftSidebar();
    }
  } catch (error) {
    logger.error("Error when toggling left sidebar", error);
  }
}

async function openLeftSidebar() {
  await vscode.commands.executeCommand("workbench.action.focusSideBar");
  isLeftSidebarVisible = true;
}

async function closeLeftSidebar() {
  await vscode.commands.executeCommand("workbench.action.closeSidebar");
  isLeftSidebarVisible = false;
}

async function openRightSidebar() {
  await vscode.commands.executeCommand("workbench.action.focusAuxiliaryBar");
}

async function closeRightSidebar() {
  await vscode.commands.executeCommand("aichat.close-sidebar");
}

async function openRawDesignFile(uri: vscode.Uri): Promise<void> {
  logger.info("openRawDesignFile", uri);

  try {
    await vscode.commands.executeCommand("vscode.openWith", uri, "default", {
      preserveFocus: false,
    });
  } catch (error) {
    logger.error("Error when opening raw design file", error);
    vscode.window.showErrorMessage("Failed to open raw design file");
  }
}

function processFirstRun(context: vscode.ExtensionContext) {
  if (!IS_DEV) {
    const firstRun = !context.globalState.get<boolean>("firstRunDone");

    if (firstRun) {
      if (vscode.window.state.focused) {
        vscode.commands.executeCommand("pencil.sidebar.focus");
        createAndOpenDocument(context, "welcome");
      } else {
        // Wait for this window to become focused, then open the first-run document.
        const disposable = vscode.window.onDidChangeWindowState((state) => {
          if (state.focused) {
            disposable.dispose();
            vscode.commands.executeCommand("pencil.sidebar.focus");
            createAndOpenDocument(context, "welcome");
          }
        });
        context.subscriptions.push(disposable);
      }
    }
  }
}

function mapWorkspaceFolders(): string[] {
  return vscode.workspace.workspaceFolders?.map((f) => f.uri.fsPath) || [];
}
