export function getSupportedModels(agentType, login) {
    if (agentType === "codex") {
        return [
            { displayName: "GPT 5.5", id: "gpt-5.5" },
            { displayName: "GPT 5.4", id: "gpt-5.4" },
            { displayName: "GPT 5.3 Codex", id: "gpt-5.3-codex" },
            { displayName: "GPT 5.4 Mini", id: "gpt-5.4-mini" },
        ];
    }
    if (agentType === "gemini") {
        return [
            { displayName: "Gemini 3.5 Flash", id: "gemini-3.5-flash" },
            { displayName: "Gemini 3.1 Pro", id: "gemini-3.1-pro-preview" },
            { displayName: "Gemini 3 Flash", id: "gemini-3-flash-preview" },
        ];
    }
    if (login === "subscription" || login === "api-key") {
        return [
            {
                displayName: "Claude Opus 4.8",
                id: "claude-opus-4-8",
                description: "Most capable, higher cost",
            },
            {
                displayName: "Claude Opus 4.7",
                id: "claude-opus-4-7",
                description: "Most capable, higher cost",
            },
            {
                displayName: "Claude Opus 4.6",
                id: "claude-opus-4-6",
                description: "Most capable, higher cost",
            },
            {
                displayName: "Claude Sonnet 5",
                id: "claude-sonnet-5",
                description: "Fast, balanced performance",
            },
            {
                displayName: "Claude Sonnet 4.6",
                id: "claude-sonnet-4-6",
                description: "Fast, balanced performance",
            },
            {
                displayName: "Claude Haiku 4.5",
                id: "claude-haiku-4-5",
                description: "Fastest, lowest cost",
            },
            {
                displayName: "Claude Fable 5",
                id: "claude-fable-5",
                description: "Most capable, higher cost",
            },
        ];
    }
    else {
        // Third-party logins may have different models available
        return [{ displayName: "Custom Model", id: "custom-model" }];
    }
}
export function getDefaultModel(agentType, login) {
    if (agentType === "codex") {
        return "gpt-5.5";
    }
    if (agentType === "gemini") {
        return "gemini-3.5-flash";
    }
    if (login === "subscription" || login === "api-key") {
        return "claude-opus-4-6";
    }
    else {
        // Third-party logins may have different models available
        return "custom-model";
    }
}
export function mapCanvasModelsToThirdParty(agentType, login, canvasModelID) {
    if (!canvasModelID) {
        return getDefaultModel(agentType, login);
    }
    if (agentType === "codex") {
        if (canvasModelID === "claude-4.5-haiku") {
            return "gpt-5.4-mini";
        }
        else if (canvasModelID === "claude-4.6-sonnet") {
            return "gpt-5.4";
        }
        else if (canvasModelID === "claude-4.6-opus") {
            return "gpt-5.5";
        }
        else {
            return canvasModelID;
        }
    }
    if (agentType === "gemini") {
        return getDefaultModel(agentType, login);
    }
    if (login === "subscription" || login === "api-key") {
        if (canvasModelID === "claude-4.5-haiku") {
            return "claude-haiku-4-5";
        }
        else if (canvasModelID === "claude-5-sonnet") {
            return "claude-sonnet-5";
        }
        else if (canvasModelID === "claude-4.5-sonnet") {
            return "claude-sonnet-5";
        }
        else if (canvasModelID === "claude-4.6-sonnet") {
            return "claude-sonnet-5";
        }
        else if (canvasModelID === "claude-4.5-opus") {
            return "claude-opus-4-5";
        }
        else if (canvasModelID === "claude-4.6-opus") {
            return "claude-opus-4-6";
        }
        else if (canvasModelID === "claude-4.7-opus") {
            return "claude-opus-4-7";
        }
        else if (canvasModelID === "claude-4.8-opus") {
            return "claude-opus-4-8";
        }
        else if (canvasModelID === "claude-5-fable") {
            return "claude-fable-5";
        }
        else {
            return canvasModelID;
        }
    }
    else {
        // Third-party logins may have different models available
        return "custom-model";
    }
}
export function getAgentTypeFromModelID(modelID) {
    if (modelID.startsWith("claude-") || modelID === "custom-model") {
        return { agentType: "claude" };
    }
    else if (modelID.startsWith("gpt-")) {
        return { agentType: "codex" };
    }
    else if (modelID.startsWith("gemini-")) {
        return { agentType: "gemini" };
    }
    else {
        const [_type, provider, _id] = modelID.split(";");
        return { agentType: "pi", provider: provider };
    }
}
export function parseToolName(fullName) {
    const parts = fullName.split("__");
    return parts.pop();
}
export function getDefaultAgentConfig() {
    const claudeModels = getSupportedModels("claude", "subscription");
    const codexModels = getSupportedModels("codex", "subscription");
    const geminiModels = getSupportedModels("gemini", "api-key");
    return {
        claude: {
            loginType: "subscription",
            apiKeyStored: false,
            defaultModel: getDefaultModel("claude", "subscription"),
            supportedModels: claudeModels,
        },
        codex: {
            loginType: "subscription",
            apiKeyStored: false,
            defaultModel: getDefaultModel("codex", "subscription"),
            supportedModels: codexModels,
        },
        gemini: {
            loginType: "api-key",
            apiKeyStored: false,
            defaultModel: getDefaultModel("gemini", "subscription"),
            supportedModels: geminiModels,
        },
        pi: [],
        allSupportedModels: [...claudeModels, ...codexModels, ...geminiModels],
    };
}
