import { existsSync, readFileSync } from "node:fs";
import * as path from "node:path";
import {
  getInitParamsForDevice,
  type IPCDeviceManager,
  type OpenExternalUrlOptions,
} from "@ha/ipc";
import { getMcpConfiguration } from "@ha/mcp";
import type { DocumentInitParams, MCPIntegration } from "@ha/shared";
import * as vscode from "vscode";
import { getEditorPath } from "./bundle-manager";
import { IS_DEV } from "./environment";
import { ExtensionIPCServer } from "./ipc-extension";
import { logger } from "./logger";
import { PencilDocument } from "./pencil-document";
import type { SidebarProvider } from "./sidebar-provider";
import { VsCodeMCPAdapter } from "./vscode-mcp-adapter";
import { isUriTemporary, VSCodeResourceDevice } from "./vscode-resource-device";

export class PencilEditorProvider implements vscode.CustomEditorProvider {
  public static readonly viewType = "pencil.designEditor";

  private readonly _onDidChangeCustomDocument = new vscode.EventEmitter<
    vscode.CustomDocumentEditEvent<PencilDocument>
  >();

  public readonly onDidChangeCustomDocument =
    this._onDidChangeCustomDocument.event;

  private isDisplayingReloadWarning = false;

  constructor(
    private readonly context: vscode.ExtensionContext,
    private readonly ipcDeviceManager: IPCDeviceManager,
    private readonly adapter: VsCodeMCPAdapter,
    private readonly sidebarProvider?: SidebarProvider,
  ) {}

  async openCustomDocument(
    vscodeUri: vscode.Uri,
    openContext: vscode.CustomDocumentOpenContext,
    _cancellation: vscode.CancellationToken,
  ): Promise<vscode.CustomDocument> {
    const uri =
      vscodeUri.scheme === "untitled"
        ? vscode.Uri.parse(atob(vscodeUri.query))
        : vscodeUri;

    logger.debug("[openCustomDocument]", uri.toString());

    const contents = openContext.backupId
      ? await vscode.workspace.fs.readFile(
          vscode.Uri.parse(openContext.backupId),
        )
      : uri.scheme === "pencil"
        ? await vscode.workspace.fs.readFile(
            vscode.Uri.file(
              path.join(
                this.context.extensionPath,
                "out",
                "data",
                uri.authority,
              ),
            ),
          )
        : await vscode.workspace.fs.readFile(uri);

    // Track non-temporary files in recent files
    if (!isUriTemporary(uri)) {
      try {
        this.sidebarProvider?.addRecentFile(uri.fsPath);
      } catch (error) {
        logger.warn("[openCustomDocument] Failed to add recent file", error);
      }
    }

    return new PencilDocument(
      vscodeUri,
      Buffer.from(contents).toString("utf8"),
    );
  }

  async resolveCustomEditor(
    document: PencilDocument,
    webviewPanel: vscode.WebviewPanel,
    _cancellation: vscode.CancellationToken,
  ): Promise<void> {
    logger.debug("[resolveCustomEditor]", document.uri.toString());
    const uri =
      document.uri.scheme === "untitled"
        ? vscode.Uri.parse(atob(document.uri.query))
        : document.uri.scheme === "pencil"
          ? vscode.Uri.from({ scheme: "pencil", path: document.uri.authority })
          : document.uri;
    const localResourceRoots = [vscode.Uri.file(path.dirname(uri.fsPath))];
    const ipc = new ExtensionIPCServer(webviewPanel.webview);
    const device = await this.createResourceDevice(document, ipc);

    document.onSave = (uri, options) =>
      ipc.request("save", {
        uri: uri.toString(),
        assignNewFileToken: options?.assignNewFileToken,
      });

    ipc.on("add-to-chat", async (message: string) => {
      try {
        await vscode.commands.executeCommand("composer.createNew", {
          autoSubmit: false,
          partialState: {
            text: message,
          },
        });
      } catch (error) {
        logger.error("Failed to insert text into Cursor chat:", error);
      }
    });

    ipc.on(
      "toggle-mcp-integration",
      async ({
        integration,
        state,
      }: {
        integration: MCPIntegration;
        state: boolean;
      }) => {
        await this.adapter.toggleIntegration(integration, state);

        let enabledIntegrations = this.context.globalState.get<
          MCPIntegration[] | undefined
        >("enabledIntegrations", undefined);

        // If enabledIntegrations are missing that means this is "first-time" with enabledIntegrations,
        // so let's use supported.
        if (!enabledIntegrations) {
          enabledIntegrations = VsCodeMCPAdapter.getSupportedIntegrations();
        }

        ipc.notify("active-integrations", {
          active: enabledIntegrations,
          supported: VsCodeMCPAdapter.getSupportedIntegrations(),
        });
      },
    );

    ipc.handle("get-active-integrations", () => {
      let enabledIntegrations = this.context.globalState.get<
        MCPIntegration[] | undefined
      >("enabledIntegrations", undefined);

      // If enabledIntegrations are missing that means this is "first-time" with enabledIntegrations,
      // so let's use supported.
      if (!enabledIntegrations) {
        enabledIntegrations = VsCodeMCPAdapter.getSupportedIntegrations();
      }

      return {
        active: enabledIntegrations,
        supported: VsCodeMCPAdapter.getSupportedIntegrations(),
      };
    });

    ipc.handle("get-mcp-config", () => {
      const mcpConfig = getMcpConfiguration({
        folderPath: this.adapter.getInstallationPath(),
        appName: this.adapter.getAppName(),
      });

      return JSON.stringify(mcpConfig);
    });

    ipc.handle("open-mcp-settings", async () => {
      return openMcpSettingsInIDE();
    });

    ipc.on<{ url: string; options?: OpenExternalUrlOptions }>(
      "open-external-url",
      ({ url, options }) => {
        device.openExternalUrl(url, options);
      },
    );

    this.ipcDeviceManager.addResource(ipc, device);
    this.ipcDeviceManager.updateLastResource(uri.toString());

    if (!IS_DEV) {
      const editorPath = getEditorPath(this.context);
      localResourceRoots.push(editorPath);
    }

    webviewPanel.webview.options = {
      enableScripts: true,
      localResourceRoots,
    };

    webviewPanel.webview.html = getWebviewContent(
      this.context,
      webviewPanel.webview,
      getInitParamsForDevice(
        device,
        this.ipcDeviceManager.getConnectedAgents(),
      ),
    );

    const viewStateListener = webviewPanel.onDidChangeViewState((e) => {
      logger.debug("[onDidChangeViewState]", uri.fsPath, e.webviewPanel.active);

      if (e.webviewPanel.active) {
        this.ipcDeviceManager.updateLastResource(uri.toString());
      }
    });

    let fileWatcher: vscode.FileSystemWatcher | undefined;

    fileWatcher = vscode.workspace.createFileSystemWatcher(uri.fsPath);

    fileWatcher.onDidChange(async (uri) => {
      logger.debug(`[fileWatcher.onDidChange] file: ${uri.toString()}`);

      await this.handleFileChange(uri, document, ipc);
    });

    fileWatcher.onDidDelete(async (uri: vscode.Uri) => {
      logger.debug(`[fileWatcher.onDidDelete] file: ${uri.toString()}`);

      await findAndCloseEditorTab(uri);
    });

    webviewPanel.onDidDispose(async () => {
      logger.debug("[webviewPanel.onDidDispose]", uri.toString());

      if (fileWatcher) {
        fileWatcher.dispose();
      }

      await this.ipcDeviceManager.removeResource(device.getResourceURI());
      viewStateListener.dispose();
      document.dispose();
    });
  }

  async saveCustomDocument(
    document: PencilDocument,
    cancellation: vscode.CancellationToken,
  ): Promise<void> {
    logger.debug("[saveCustomDocument]", document.uri.toString());

    const device = this.ipcDeviceManager.getResourceDevice(document.uri.fsPath);

    // In extension we handle document save outside of ResourceDevice, in
    // ResourceDevice we only handle linked resources like images.
    await document.save(cancellation);
    await device?.saveResource({
      userAction: true,
      destinationPath: document.uri.fsPath,
    });
  }

  async saveCustomDocumentAs(
    document: PencilDocument,
    destination: vscode.Uri,
    cancellation: vscode.CancellationToken,
  ): Promise<void> {
    logger.debug("[saveCustomDocumentAs]", document.uri.toString());

    const device = this.ipcDeviceManager.getResourceDevice(document.uri.fsPath);

    // In extension we handle document saveAs outside of ResourceDevice, in
    // ResourceDevice we only handle linked resources like images.
    await document.saveAs(destination, cancellation, {
      assignNewFileToken: true,
    });
    await device?.saveResource({
      userAction: true,
      saveAs: true,
      destinationPath: destination.fsPath,
    });

    // Track newly saved files in recent files
    try {
      this.sidebarProvider?.addRecentFile(destination.fsPath);
    } catch (error) {
      logger.warn("[saveCustomDocumentAs] Failed to add recent file", error);
    }
  }

  revertCustomDocument(
    document: PencilDocument,
    cancellation: vscode.CancellationToken,
  ): Thenable<void> {
    logger.debug("[revertCustomDocument]", document.uri.toString());

    return document.revert(cancellation);
  }

  backupCustomDocument(
    document: PencilDocument,
    context: vscode.CustomDocumentBackupContext,
    cancellation: vscode.CancellationToken,
  ): Thenable<vscode.CustomDocumentBackup> {
    logger.debug("[backupCustomDocument]", document.uri.toString());

    return document.backup(context.destination, cancellation);
  }

  private async createResourceDevice(
    document: PencilDocument,
    ipc: ExtensionIPCServer,
  ): Promise<VSCodeResourceDevice> {
    return new VSCodeResourceDevice(
      this.context,
      document,
      () => {
        this._onDidChangeCustomDocument.fire({
          document,
          label: "Pencil Editor Change",
          undo: async () => {
            ipc.notify("undo");
          },
          redo: async () => {
            ipc.notify("redo");
          },
        });
      },
      (uri) => {
        ipc.notify("file-changed", uri);
      },
    );
  }

  private async handleFileChange(
    uri: vscode.Uri,
    document: PencilDocument,
    ipc: ExtensionIPCServer,
  ): Promise<void> {
    const newContent = Buffer.from(
      await vscode.workspace.fs.readFile(uri),
    ).toString("utf8");
    const oldContent = document.getContent();

    // Trimming text contents, to avoid detection of leading or trailing
    // whitespaces.
    if (oldContent.trim() === newContent.trim()) {
      return;
    }

    // NOTE(zaza): closing a document and discarding unsaved changes generates a final `onDidChangeTextDocument`
    // (because the document model is reverted internally to the last saved state) event before disposing the editor.
    // There's no other way to distinguish this final event from legitimate external changes than waiting a bit to
    // see if the editor is going to be disposed of. If the editor wasn't disposed after 500ms, we're assuming the
    // event to be due to a legit external change, and display the warning.
    setTimeout(async () => {
      if (document.isDisposed || this.isDisplayingReloadWarning) {
        return;
      }

      this.isDisplayingReloadWarning = true;
      const reloadResponse = await vscode.window.showWarningMessage(
        `The contents of ${path.basename(uri.fsPath)} have changed! Do you want to reload it?`,
        "Reload",
        "Ignore",
      );
      this.isDisplayingReloadWarning = false;

      if (reloadResponse === "Reload") {
        ipc.notify("file-update", {
          content: newContent,
          fileURI: uri.toString(),
          isDirty: false,
        });
      }
    }, 500);
  }
}

function getWebviewContent(
  context: vscode.ExtensionContext,
  webview: vscode.Webview,
  initParams: DocumentInitParams,
): string {
  if (IS_DEV) {
    return `
      <!DOCTYPE html>
      <html lang="en">
      <head>
        <meta charset="UTF-8">
        <meta http-equiv="Content-Security-Policy" content="default-src 'none'; script-src 'unsafe-inline' 'unsafe-eval' http://localhost:3000 https://*.posthog.com; style-src 'unsafe-inline' http://localhost:3000 https://fonts.googleapis.com; font-src blob: https://fonts.gstatic.com https://unpkg.com https://hctfc8iexhqk0x3o.public.blob.vercel-storage.com; connect-src data: blob: http://localhost:3000 ws://localhost:3000 https://fonts.gstatic.com https://unpkg.com https://hctfc8iexhqk0x3o.public.blob.vercel-storage.com http://api.localhost:3001 https://api.pencil.dev https://*.ingest.us.sentry.io https://api.reve.com https://*.posthog.com https://images.unsplash.com https://status.claude.com https://status.openai.com https://status.cloud.google.com; img-src data: blob: http://localhost:3000 https://images.unsplash.com https://hctfc8iexhqk0x3o.public.blob.vercel-storage.com; worker-src blob:;">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>Editor</title>
        <script type="module">
        import RefreshRuntime from "http://localhost:3000/@react-refresh"
        RefreshRuntime.injectIntoGlobalHook(window)
        window.$RefreshReg$ = () => {}
        window.$RefreshSig$ = () => (type) => type
        window.__vite_plugin_react_preamble_installed__ = true
        </script>
      </head>
      <body>
        <div id="root"></div>
        <script>
          const vscode = acquireVsCodeApi();
          window.vscodeapi = vscode;
          window.PENCIL_APP_NAME = "${vscode.env.appName}";
          window.PENCIL_INIT_PARAMS = ${JSON.stringify(initParams)};
          window.IS_DEV = true;

          // Handle messages from extension
          window.addEventListener('message', (event) => {
            if (event.data?.source === 'vscode-extension' && event.source === window) {
              // Forward to app
              window.postMessage(event.data, '*');
            }
          });

          // Handle messages from app
          window.addEventListener('message', (event) => {
            if (event.data?.source === 'application' && event.source === window) {
              vscode.postMessage(event.data);
            }
          });
        </script>
        <script type="module" src="http://localhost:3000/src/main.tsx"></script>
      </body>
      </html>
    `;
  } else {
    const editorPathUri = getEditorPath(context);
    const editorPath = editorPathUri.fsPath;
    const indexHtmlPath = path.join(editorPath, "index.html");

    if (!existsSync(indexHtmlPath)) {
      return "<html><body><h1>Error: Built assets not found. Please build the editor first.</h1></body></html>";
    }

    let htmlContent = readFileSync(indexHtmlPath, "utf8");

    // Convert asset paths to vscode-webview URIs
    const assetUri = webview.asWebviewUri(editorPathUri);
    htmlContent = htmlContent.replace(
      /href="\.\/assets\//g,
      `href="${assetUri}/assets/`,
    );
    htmlContent = htmlContent.replace(
      /src="\.\/assets\//g,
      `src="${assetUri}/assets/`,
    );

    htmlContent = htmlContent.replace(/ crossorigin/g, "");

    // Replace any existing CSP with one that includes PostHog and VSCode webview resources
    const productionCSP = `<meta http-equiv="Content-Security-Policy" content="default-src 'none'; script-src 'unsafe-inline' 'unsafe-eval' ${webview.cspSource} https://*.posthog.com; style-src 'unsafe-inline' ${webview.cspSource} https://fonts.googleapis.com; font-src ${webview.cspSource} blob: https://fonts.gstatic.com https://unpkg.com https://hctfc8iexhqk0x3o.public.blob.vercel-storage.com; connect-src data: blob: ${webview.cspSource} https://api.pencil.dev https://fonts.gstatic.com https://unpkg.com https://hctfc8iexhqk0x3o.public.blob.vercel-storage.com https://*.ingest.us.sentry.io https://*.posthog.com https://api.reve.com https://images.unsplash.com https://status.claude.com https://status.openai.com https://status.cloud.google.com; img-src data: blob: ${webview.cspSource} https://images.unsplash.com https://hctfc8iexhqk0x3o.public.blob.vercel-storage.com; worker-src blob: data:;">`;

    if (/<meta[^>]*Content-Security-Policy[^>]*>/gi.test(htmlContent)) {
      // Replace existing CSP
      htmlContent = htmlContent.replace(
        /<meta[^>]*Content-Security-Policy[^>]*>/gi,
        productionCSP,
      );
    } else {
      // Add CSP to <head> if it doesn't exist
      htmlContent = htmlContent.replace(
        /<head>/i,
        `<head>\n    ${productionCSP}`,
      );
    }

    const wasmPath = path.join(editorPath, "assets", "pencil.wasm");
    let wasmData = "";
    if (existsSync(wasmPath)) {
      const wasmBuffer = readFileSync(wasmPath);
      wasmData = `window.canvaskitWasm = new Uint8Array([${Array.from(wasmBuffer).join(",")}]);`;
    }

    const vscodeScript = `
        <script>
          const vscode = acquireVsCodeApi();
          window.vscodeapi = vscode;
          window.VSCODE_WEBVIEW_BASE_URI = "${assetUri}/";
          window.PENCIL_APP_NAME = "${vscode.env.appName}";
          window.PENCIL_INIT_PARAMS = ${JSON.stringify(initParams)};

          ${wasmData}

          // Handle messages from extension
          window.addEventListener('message', (event) => {
            if (event.data?.source === 'vscode-extension' && event.source === window) {
              // Forward to app
              window.postMessage(event.data, '*');
            }
          });

          // Handle messages from app
          window.addEventListener('message', (event) => {
            if (event.data?.source === 'application' && event.source === window) {
              vscode.postMessage(event.data);
            }
          });
        </script>
      </body>`;

    htmlContent = htmlContent.replace("</body>", vscodeScript);

    return htmlContent;
  }
}

async function findAndCloseEditorTab(uri: vscode.Uri): Promise<void> {
  const tabs = vscode.window.tabGroups.all.flatMap((group) => group.tabs);

  const tab = tabs.find((tab) => {
    const input = tab.input;
    if (input instanceof vscode.TabInputCustom) {
      return (
        input.viewType === PencilEditorProvider.viewType &&
        input.uri.toString() === uri.toString()
      );
    }
    return false;
  });

  if (tab) {
    await vscode.window.tabGroups.close(tab);
  }
}

async function openMcpSettingsInIDE(): Promise<boolean> {
  const explicitCommandByApp: Record<string, string> = {
    Antigravity: "antigravity.openConfigurePluginsPage",
    Cursor: "workbench.action.openMCPSettings",
    "Visual Studio Code": "aiCustomization.openManagementEditor",
    "Visual Studio Code - Insiders": "aiCustomization.openManagementEditor",
  };

  const explicit = explicitCommandByApp[vscode.env.appName];
  if (explicit) {
    try {
      await vscode.commands.executeCommand(explicit);
      return true;
    } catch (error) {
      logger.warn(
        `MCP settings command "${explicit}" failed for ${vscode.env.appName}`,
        error,
      );
    }
  }

  // Fallback for forks / older versions where we don't know the exact id.
  const fallbackCommands = [
    "workbench.action.chat.openMCPServers",
    "workbench.action.mcp.listServers",
    "workbench.action.openMcpServers",
    "workbench.mcp.listServers",
    "workbench.mcp.openSettings",
    "mcp.openServers",
    "mcp.openSettings",
  ];

  for (const command of fallbackCommands) {
    try {
      await vscode.commands.executeCommand(command);
      return true;
    } catch {
      // Not registered on this host - try the next candidate.
    }
  }

  try {
    // Last-resort fallback: open the Settings UI filtered to MCP entries so
    // the user can find the right toggle even if no dedicated command exists.
    await vscode.commands.executeCommand(
      "workbench.action.openSettings",
      "mcp",
    );
    return true;
  } catch {
    // Not registered on this host - try the next candidate.
  }

  return false;
}
