import { spawnSync } from "node:child_process";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import {
  activateIntegrations,
  getMcpBinaryName,
  type MCPSetupPlatformAdapter,
  removeIntegrations,
} from "@ha/mcp";
import type { MCPIntegration } from "@ha/shared";
import * as vscode from "vscode";
import { CONFIG_FOLDER, EXTENSION_PATH } from "./contants";
import { IS_DEV } from "./environment";
import { logger } from "./logger";

/**
 * Returns the stable MCP installation path (~/.pencil/mcp/<appName>).
 * The binary lives at <stablePath>/out/<binaryName>, matching the
 * layout getMcpConfiguration expects.
 */
function getStableMcpPath(appName: string): string {
  return path.join(CONFIG_FOLDER, "mcp", appName);
}

/**
 * Copy the platform-specific MCP binary to the stable path so security
 * allowlists survive extension updates. Falls back to extension path
 * if the copy fails. Skipped in dev mode where the binary is used
 * directly from the extension/repo path.
 */
function copyMcpBinaryToStablePath(appName: string): boolean {
  if (IS_DEV) {
    return false;
  }

  const binaryName = getMcpBinaryName();
  const src = path.join(EXTENSION_PATH, "out", binaryName);
  const destDir = path.join(getStableMcpPath(appName), "out");
  const dest = path.join(destDir, binaryName);

  try {
    fs.mkdirSync(destDir, { recursive: true });
    fs.copyFileSync(src, dest);
    fs.chmodSync(dest, 0o755);
    logger.info(`Copied MCP binary to ${dest}`);
    if (os.platform() === "darwin") {
      const xattrResult = spawnSync(
        "xattr",
        ["-d", "com.apple.quarantine", dest],
        { encoding: "utf8" },
      );
      if (xattrResult.status !== 0) {
        logger.error(
          `Failed to remove com.apple.quarantine xattr`,
          xattrResult,
        );
      }
    }
    return true;
  } catch (err: any) {
    logger.error(`Failed to copy MCP binary: ${err.message}`);
    return false;
  }
}

/**
 * VSCode extension platform adapter for MCP setup.
 */
export class VsCodeMCPAdapter implements MCPSetupPlatformAdapter {
  log = logger;
  private stablePathAvailable = false;

  constructor(private readonly context: vscode.ExtensionContext) {
    this.stablePathAvailable = copyMcpBinaryToStablePath(this.getAppName());
  }

  getInstallationPath(): string {
    if (this.stablePathAvailable) {
      return getStableMcpPath(this.getAppName());
    }
    return EXTENSION_PATH;
  }

  getExternalExtensionPath(extensionId: string): string | undefined {
    return vscode.extensions.getExtension(extensionId)?.extensionPath;
  }

  getAppPath(): string {
    return path.resolve(
      path.dirname(this.context.globalStorageUri.fsPath),
      "..",
    );
  }

  getAppName(): string {
    return vscode.env.appName.trim().toLowerCase().replaceAll(" ", "_");
  }

  static getSupportedIntegrations(): MCPIntegration[] {
    const integrations: MCPIntegration[] = [
      "claudeCodeCLI",
      "codexCLI",
      "geminiCLI",
      "openCodeCLI",
      "kiroCLI",
      "claudeDesktop",
    ];

    if (vscode.env.appName.startsWith("Visual Studio Code")) {
      integrations.push("copilotIDE");
    } else if (vscode.env.appName === "Antigravity") {
      integrations.push("antigravityIDE");
    } else if (vscode.env.appName === "Windsurf") {
      integrations.push("windsurfIDE");
    }

    return integrations;
  }

  async setupIntegrations(
    enabledIntegrations?: MCPIntegration[],
  ): Promise<void> {
    try {
      // If enabledIntegrations are missing that means this is "first-time" with enabledIntegrations,
      // so let's use supported.
      if (!enabledIntegrations) {
        enabledIntegrations = VsCodeMCPAdapter.getSupportedIntegrations();
      }

      const supportedIntegrations = VsCodeMCPAdapter.getSupportedIntegrations();

      enabledIntegrations = enabledIntegrations.filter((i) =>
        supportedIntegrations.includes(i),
      );

      // Remove the union of enabled and supported integrations, so we can clean
      // up integrations that got unspported.
      const toRemove = [
        ...new Set([...enabledIntegrations, ...supportedIntegrations]),
      ];

      // Always make sure to remove "cursorCLI" integration in Cursor because
      // we use Cursor's own API.
      if (vscode.env.appName === "Cursor" && !toRemove.includes("cursorCLI")) {
        toRemove.push("cursorCLI");
      }

      await removeIntegrations(this, toRemove);

      const activeIntegrations = await activateIntegrations(
        this,
        enabledIntegrations,
      );

      this.context.globalState.update(
        "enabledIntegrations",
        activeIntegrations,
      );

      logger.info("MCP integrations setup completed", activeIntegrations);
    } catch (error) {
      logger.error("Failed to setup MCP integrations:", error);
    }
  }

  /**
   * Remove all MCP integrations from external tools.
   * Called when extension is deactivated/uninstalled.
   */
  async cleanup(): Promise<void> {
    // Do not cleanup integrations on app quit, because we can reconnect
    // automatically.
    // try {
    //   await removeIntegrations(this, this.getSupportedIntegrations());
    //   logger.info("Cleaned up all MCP integrations from external tools");
    // } catch (error) {
    //   logger.error("Failed to cleanup MCP integrations", error);
    // }
  }

  async toggleIntegration(
    integration: MCPIntegration,
    state: boolean,
  ): Promise<void> {
    const supportedIntegrations = VsCodeMCPAdapter.getSupportedIntegrations();

    if (!supportedIntegrations.includes(integration)) {
      logger.warn(`cannot enable unsupported integration: ${integration}`);
      return;
    }

    let enabledIntegrations = this.context.globalState.get<
      MCPIntegration[] | undefined
    >("enabledIntegrations", undefined);

    // If enabledIntegrations are missing that means this is "first-time" with enabledIntegrations,
    // so let's use supported.
    if (!enabledIntegrations) {
      enabledIntegrations = supportedIntegrations;
    }

    if (state) {
      if (!enabledIntegrations.includes(integration)) {
        enabledIntegrations.push(integration);
      }
    } else {
      enabledIntegrations = enabledIntegrations.filter(
        (i) => i !== integration,
      );
    }

    await this.setupIntegrations(enabledIntegrations);
  }
}
