import fs from "node:fs";
import semver from "semver";
import * as vscode from "vscode";
import { PENCIL_EXTENSION_ID } from "./contants";
import { logger } from "./logger";

export async function checkForExtensionUpdate(): Promise<boolean> {
  logger.info("Checking for new extension version...");

  const ext = vscode.extensions.getExtension(PENCIL_EXTENSION_ID);
  if (!ext) {
    return false;
  }
  const installedVersion = ext.packageJSON.version as string;
  const isPrerelease = isVersionPrerelease(installedVersion);

  try {
    logger.info(`checking update for ${isPrerelease ? "pre-" : ""}release`);

    const installedVersion = ext.packageJSON.version;

    let latestVersion = await getOpenVSXLatestRelease(isPrerelease);
    logger.info("latest released extension version on OpenVSX", latestVersion);

    // In Cursor use their own API to detect new versions.
    if (vscode.cursor) {
      latestVersion = await getLatestCursorRelease(isPrerelease);
      logger.info("latest released extension version on Cursor", latestVersion);
    }

    logger.info("currently installed extension version", installedVersion);

    if (!latestVersion) {
      return false;
    }

    if (semver.lte(latestVersion, installedVersion)) {
      return false;
    }

    logger.info("update available!");

    const newExtensionPath = ext.extensionPath.replaceAll(
      installedVersion,
      latestVersion,
    );

    let stats = null;
    try {
      stats = fs.statSync(`${newExtensionPath}-universal`);
    } catch (_err: any) {}

    if (stats?.isDirectory()) {
      logger.info("update already installed, prompting for reload");
      const resp = await vscode.window.showInformationMessage(
        `Pencil update installed: ${latestVersion}. Restart extension to take effect`,
        "Open",
        "Ignore",
      );

      if (resp === "Ignore") {
        return false;
      } else if (resp === "Open") {
        await vscode.commands.executeCommand(
          "extension.open",
          PENCIL_EXTENSION_ID,
        );
      }

      return true;
    }

    const resp = await vscode.window.showInformationMessage(
      `Pencil update available. Go to extension to install.`,
      "Open",
      "Ignore",
    );

    if (resp === "Ignore") {
      return false;
    } else if (resp === "Open") {
      await vscode.commands.executeCommand(
        "extension.open",
        PENCIL_EXTENSION_ID,
      );
    }

    return true;
  } catch (err: any) {
    logger.warn("failed to check for update", err);
  }

  return false;
}

function isVersionPrerelease(v: string): boolean {
  return Number(v.split(".")[1]) % 2 === 1;
}

async function getOpenVSXLatestRelease(
  isPrerelease: boolean,
): Promise<string | undefined> {
  const releaseType = isPrerelease ? "pre-release" : "latest";

  const resp = await fetch(
    `https://open-vsx.org/api/${PENCIL_EXTENSION_ID.replaceAll(".", "/")}/${releaseType}`,
    {
      method: "GET",
    },
  );

  if (!resp.ok) {
    return undefined;
  }

  const body = (await resp.json()) as { version: string };
  return body.version;
}

async function getLatestCursorRelease(
  isPrerelease: boolean,
): Promise<string | undefined> {
  const resp = await fetch(
    "https://marketplace.cursorapi.com/_apis/public/gallery/extensionquery",
    {
      method: "POST",
      headers: {
        Accept: "application/json;api-version=3.0-preview.1",
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        filters: [
          {
            criteria: [{ filterType: 1, value: PENCIL_EXTENSION_ID }],
            pageNumber: 1,
            pageSize: 1,
            sortBy: 0,
            sortOrder: 0,
          },
        ],
        assetTypes: [],
        flags: 55,
      }),
    },
  );

  if (!resp.ok) {
    return undefined;
  }

  const body = (await resp.json()) as any;

  if (!body.results || body.results.length === 0) {
    return undefined;
  }

  const pencilExtension = body.results[0].extensions.find(
    (ext: any) => ext.extensionName === "pencildev",
  );

  if (!pencilExtension) {
    return undefined;
  }

  const versions = pencilExtension.versions.map((v: any) => v.version);

  if (isPrerelease) {
    for (const v of versions) {
      if (isVersionPrerelease(v)) {
        return v;
      }
    }
    return undefined;
  }

  for (const v of versions) {
    if (!isVersionPrerelease(v)) {
      return v;
    }
  }

  return undefined;
}
