import os from "node:os";
import path from "node:path";
import vscode from "vscode";

export const PENCIL_EXTENSION_ID = "highagency.pencildev";

export const PENCIL_MCP_NAME = "pencil";

// Our extension needs to exist.
export const EXTENSION_PATH =
  vscode.extensions.getExtension(PENCIL_EXTENSION_ID)!.extensionPath;

export const CONFIG_FOLDER = path.join(os.homedir(), ".pencil");

export const DOCUMENTS_FOLDER = path.join(CONFIG_FOLDER, "documents");
