import * as fs from "node:fs";
import * as path from "node:path";
import * as vscode from "vscode";

const MAX_RECENT_FILES = 7;

type SidebarItem =
  | NewFileItem
  | RecentFileItem
  | ClearRecentFilesItem
  | SeparatorItem
  | DesignKitItem;

export class SidebarProvider implements vscode.TreeDataProvider<SidebarItem> {
  private _onDidChangeTreeData = new vscode.EventEmitter<
    SidebarItem | undefined
  >();
  readonly onDidChangeTreeData = this._onDidChangeTreeData.event;

  private static readonly designKits = [
    { name: "Welcome", command: "pencil.openWelcomeDocument" },
    { name: "Shadcn UI", command: "pencil.openShadcnDocument" },
    { name: "Halo", command: "pencil.openHaloDocument" },
    { name: "Lunaris", command: "pencil.openLunarisDocument" },
    { name: "Nitro", command: "pencil.openNitroDocument" },
    { name: "Demo", command: "pencil.openDemoDocument" },
  ];

  constructor(private context: vscode.ExtensionContext) {}

  refresh(): void {
    this._onDidChangeTreeData.fire(undefined);
  }

  getTreeItem(element: SidebarItem): vscode.TreeItem {
    return element;
  }

  getChildren(): SidebarItem[] {
    const items: SidebarItem[] = [];

    items.push(new NewFileItem());

    const recentFiles = this.getRecentFiles();
    for (const filePath of recentFiles) {
      items.push(new RecentFileItem(filePath, this.context.extensionUri));
    }

    if (recentFiles.length > 0) {
      items.push(new ClearRecentFilesItem());
    }

    items.push(new SeparatorItem());

    for (const kit of SidebarProvider.designKits) {
      items.push(new DesignKitItem(kit.name, kit.command));
    }

    return items;
  }

  addRecentFile(filePath: string): void {
    if (!path.isAbsolute(filePath)) {
      return;
    }

    const recentFiles = this.context.globalState.get<string[]>(
      "recentFiles",
      [],
    );
    const filtered = recentFiles.filter((f) => f !== filePath);
    const updated = [filePath, ...filtered].slice(0, MAX_RECENT_FILES);
    this.context.globalState.update("recentFiles", updated);
    this.refresh();
  }

  getRecentFiles(): string[] {
    const recentFiles = this.context.globalState.get<string[]>(
      "recentFiles",
      [],
    );
    return recentFiles.filter((f) => fs.existsSync(f));
  }

  clearRecentFiles(): void {
    this.context.globalState.update("recentFiles", []);
    this.refresh();
  }
}

class NewFileItem extends vscode.TreeItem {
  constructor() {
    super("New .pen file", vscode.TreeItemCollapsibleState.None);

    this.command = {
      command: "pencil.newFile",
      title: "New .pen file",
    };
    this.iconPath = new vscode.ThemeIcon("add");
    this.contextValue = "newFile";
  }
}

class RecentFileItem extends vscode.TreeItem {
  constructor(
    public readonly filePath: string,
    extensionUri: vscode.Uri,
  ) {
    super(path.basename(filePath), vscode.TreeItemCollapsibleState.None);

    this.tooltip = filePath;
    this.description = this.getShortPath(filePath);
    this.command = {
      command: "vscode.open",
      title: "Open File",
      arguments: [vscode.Uri.file(filePath)],
    };
    this.contextValue = "recentFile";
    this.iconPath = {
      light: vscode.Uri.joinPath(extensionUri, "assets/icons/pencil-light.png"),
      dark: vscode.Uri.joinPath(extensionUri, "assets/icons/pencil-dark.png"),
    };
  }

  private getShortPath(filePath: string): string {
    const dir = path.dirname(filePath);
    const parts = dir.split(path.sep);
    if (parts.length > 2) {
      return `.../${parts.slice(-2).join("/")}`;
    }
    return dir;
  }
}

class ClearRecentFilesItem extends vscode.TreeItem {
  constructor() {
    super("Clear Recent Files", vscode.TreeItemCollapsibleState.None);

    this.command = {
      command: "pencil.clearRecentFiles",
      title: "Clear Recent Files",
    };
    this.iconPath = new vscode.ThemeIcon("clear-all");
    this.contextValue = "clearRecentFiles";
  }
}

class SeparatorItem extends vscode.TreeItem {
  constructor() {
    super("", vscode.TreeItemCollapsibleState.None);

    this.description = "────────────────";
    this.contextValue = "separator";
  }
}

class DesignKitItem extends vscode.TreeItem {
  constructor(label: string, commandId: string) {
    super(label, vscode.TreeItemCollapsibleState.None);

    this.command = {
      command: commandId,
      title: `Open ${label}`,
    };
    this.iconPath = new vscode.ThemeIcon("symbol-color");
    this.contextValue = "designKit";
  }
}
