/**
 * VSCode Extension side IPC handler
 */

import type { IPCMessage } from "@ha/shared";
import { IPCHost } from "@ha/shared";
import type { Webview } from "vscode";
import { logger } from "./logger";

export class ExtensionIPCServer extends IPCHost {
  constructor(webview: Webview) {
    const onMessage = (callback: (message: IPCMessage) => void) => {
      const disposable = webview.onDidReceiveMessage((message: IPCMessage) =>
        callback(message),
      );
      return () => {
        disposable.dispose();
      };
    };
    const sendMessage = (message: IPCMessage) => webview.postMessage(message);

    super(onMessage, sendMessage, logger);
    logger.info("[ExtensionIPCServer] Initializing IPC server");
  }
}
